219	    render(<Links siteId="test-site" />);
220	
221	    fireEvent.click(screen.getByText('Create token'));
222	    expect(screen.getByTestId('grant-form')).toBeInTheDocument();
223	
224	    fireEvent.click(screen.getByRole('button', { name: 'Cancel' }));
225	    expect(screen.queryByTestId('grant-form')).not.toBeInTheDocument();
226	  });
227	
228	  it('shows remote links section conditionally', () => {
229	    vi.mocked(useLinks).mockReturnValue({
230	      data: { ...mockData, remoteLinks: [] },
231	      loading: false,
232	      actions: mockActions
233	    });
234	
235	    const { rerender } = render(<Links siteId="test-site" />);
236	    expect(screen.queryByText('Links from remote sites')).not.toBeInTheDocument();
237	
