239	      data: mockData,
240	      loading: false,
241	      actions: mockActions
242	    });
243	
244	    rerender(<Links siteId="test-site" />);
245	    expect(screen.getByText('Links from remote sites')).toBeInTheDocument();
246	  });
247	});

